import os
from datetime import datetime, timedelta
from functools import wraps
import jwt
from flask import Flask, request, jsonify

app = Flask(__name__)

# --- Configuration ---
# Generate a strong, random secret key for JWT signing
# In a real application, load this from environment variables or a configuration file
app.config['SECRET_KEY'] = os.environ.get('FLASK_SECRET_KEY', 'your_super_secret_key_change_me')
app.config['JWT_ALGORITHM'] = 'HS256'
app.config['JWT_EXPIRATION_DELTA_SECONDS'] = 3600  # Token valid for 1 hour

# --- Dummy User Database (for demonstration) ---
users = {
    "user1": {"password": "password1"},
    "user2": {"password": "password2"}
}

# --- Helper Functions ---
def generate_token(user_id):
    payload = {
        'user_id': user_id,
        'exp': datetime.utcnow() + timedelta(seconds=app.config['JWT_EXPIRATION_DELTA_SECONDS'])
    }
    return jwt.encode(payload, app.config['SECRET_KEY'], algorithm=app.config['JWT_ALGORITHM'])

def verify_token(token):
    try:
        payload = jwt.decode(token, app.config['SECRET_KEY'], algorithms=[app.config['JWT_ALGORITHM']])
        return payload
    except jwt.ExpiredSignatureError:
        return {"error": "Token has expired."}
    except jwt.InvalidTokenError:
        return {"error": "Invalid token."}

# --- Decorator for Protected Endpoints ---
def token_required(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        token = None
        # Check for Authorization header
        if 'Authorization' in request.headers:
            auth_header = request.headers['Authorization']
            if auth_header.startswith('Bearer '):
                token = auth_header.split(" ")[1]

        if not token:
            return jsonify({"message": "Token is missing!"}), 401

        try:
            data = verify_token(token)
            if "error" in data:
                return jsonify({"message": data["error"]}), 401
            current_user = data['user_id']
        except Exception as e:
            return jsonify({"message": "Token is invalid!", "error": str(e)}), 401

        return f(current_user, *args, **kwargs)

    return decorated

# --- API Endpoints ---

@app.route('/login', methods=['POST'])
def login():
    auth = request.json
    if not auth or not auth.get('username') or not auth.get('password'):
        return jsonify({"message": "Could not verify", "WWW-Authenticate": "Basic realm='Login required!'"}), 401

    username = auth.get('username')
    password = auth.get('password')

    user = users.get(username)

    if not user or user['password'] != password:
        return jsonify({"message": "Could not verify", "WWW-Authenticate": "Basic realm='Login required!'"}), 401

    token = generate_token(username)
    return jsonify({"token": token})

@app.route('/protected', methods=['GET'])
@token_required
def protected_endpoint(current_user):
    return jsonify({"message": f"Hello, {current_user}! You accessed a protected resource."})

@app.route('/public', methods=['GET'])
def public_endpoint():
    return jsonify({"message": "This is a public endpoint. Anyone can see this."})

@app.route('/whoami', methods=['GET'])
@token_required
def whoami(current_user):
    return jsonify({"user": current_user, "message": "You are logged in."})

